#Requires -Version 5.1\n\n$api_key = $env:OPENROUTER_API_KEY\nif (-not $api_key) {\n    Write-Error \"OPENROUTER_API_KEY environment variable is missing\"\n    exit 1\n}\n\nfunction Get-OpenRouterModels {\n  param (\n    [string]$apiKey = $env:OPENROUTER_API_KEY\n  )\n  $url = \"https://openrouter.ai/api/v1/models\"\n  $headers = @{\n    \"Authorization\" = \"Bearer $apiKey\"\n  }\n  try {\n    $response = Invoke-RestMethod -Uri $url -Method Get -Headers $headers\n    return $response.data | Where-Object { $_.info -and $_.info.free -eq $true -and $_.context_length -gt 0 }\n  } catch {\n    Write-Error \"OpenRouter API failed: $($_.Exception.Message)\"\n    return @()\n  }\n}\n\nfunction Get-EstimatedLatency($context_window) {\n    if ($context_window -gt 100000) {\n        return 30000\n    } elseif ($context_window -gt 20000) {\n        return 10000\n    } else {\n        return 3000\n    }\n}\n\n# Fetch models from OpenRouter\n$free_models = Get-OpenRouterModels\n\n# Process models for cache update\n$models_list = $free_models | ForEach-Object {\n    [PSCustomObject]@{\n        name = $_.id\n        context_window = $_.context_window\n        provider = \"openrouter\"\n        tool_call_ok = $false\n        estimated_latency = Get-EstimatedLatency $_.context_window\n    }\n}\n\n# Fetch NVIDIA NIM models\n$nvidia_api_key = $env:NVIDIA_API_KEY\nif ($nvidia_api_key) {\n    $url = \"https://api.nvidia.com/v1/models\"\n    $headers = @{\n        \"Authorization\" = \"Bearer $nvidia_api_key\"\n    }\n    try {\n        $response = Invoke-RestMethod -Uri $url -Method Get -Headers $headers\n        # Adjust based on actual API response structure\n        $nvidia_models = $response.data | Where-Object { $_.is_available -eq $true }\n        $nvidia_models | ForEach-Object {\n            [PSCustomObject]@{\n                name = $_.id\n                context_window = $_.context_length\n                provider = \"nvidia\"\n                tool_call_ok = $false\n                estimated_latency = Get-EstimatedLatency $_.context_length\n            }\n        } | ForEach-Object { $models_list += $_ }\n    } catch {\n        Write-Error \"NVIDIA API failed: $($_.Exception.Message)\"\n    }\n} else {\n    Write-Host \"NVIDIA_API_KEY not set. Skipping NVIDIA models.\"\n}\n\n# Load existing cache\n$cache_path = \"model-metadata.json\"\nif (Test-Path $cache_path) {\n    $cached_models = Get-Content $cache_path | ConvertFrom-Json\n} else {\n    $cached_models = @{\n        last_updated = [DateTime]::UtcNow.ToString(\"o\")\n        models = @()\n    }\n}\n\n# Merge models and update last updated\n$merged_models = @($cached_models.models) + @($models_list)\n$unique_models = $merged_models | Sort-Object name -Unique\n\n$new_cache = @{\n    last_updated = (Get-Date).ToString(\"o\")\n    models = $unique_models\n}\n\n# Save updated cache\n$new_cache | ConvertTo-Json -Depth 5 | Set-Content $cache_path\n\n# Select best model based on estimated_latency\nif ($unique_models.Count -gt 0) {\n    $best_model = $unique_models | Sort-Object estimated_latency | Select-Object -First 1 | Select-Object -ExpandProperty name\n    # Create config directory if needed\n    if (-not (Test-Path \"config\")) {\n        New-Item \"config\" -ItemType Directory -Force\n    }\n    $best_model_config = @{\n        best_model = $best_model\n    }\n    $best_model_config | ConvertTo-Json | Set-Content \"config\model-config.json\"\n} else {\n    Write-Error \"No models found. Please check API keys and internet access.\"\n}